// ── RESOLVE CITY → CLIMATE ENTRY ─────────────────────────────────────────────
function resolveCityClimate(cityInput) {
  if (!cityInput) return null;
  const q = cityInput.trim().toLowerCase();
  for (const entry of CITY_CLIMATE_MAP) {
    if (entry.keys.some(k => q.includes(k) || k.includes(q))) return entry;
  }
  return null;
}

// ── SUITABILITY SCORE ─────────────────────────────────────────────────────────
// Returns 3 (Best), 2 (Good), 1 (Possible), 0 (Not recommended)
function getPlantSuitability(plant, zone) {
  if (!zone || !plant.climate) return 2;
  if (plant.climate.best && plant.climate.best.includes(zone)) return 3;
  if (plant.climate.good && plant.climate.good.includes(zone)) return 2;
  if (plant.climate.possible && plant.climate.possible.includes(zone)) return 1;
  return 0;
}

