// ADMIN OVERRIDES — load edited plants from admin panel
// Can be re-run when localStorage changes (storage event)
// ══════════════════════════════════════════
function applyAdminPlantOverrides() {
  try {
    const s = localStorage.getItem('np_admin_plants');
    if (!s) return;
    const overrides = JSON.parse(s);
    if (!Array.isArray(overrides) || !overrides.length) return;
    overrides.forEach(edited => {
      const idx = PLANT_DB.findIndex(p => p.id === edited.id);
      if (idx > -1) PLANT_DB[idx] = edited;
      else PLANT_DB.push(edited);
    });
  } catch(e) {}
}
applyAdminPlantOverrides();
